/// <summary>
/// method to enable/disable form controls
/// </summary>
public int active()
{
    int ret = next active();
    this.updateInventJournalTranferDesign();

    return ret;
}

/// <summary>
/// method to make InventJournalTransfer form non editable under conditions provided in inventory parameters.
/// </summary>
public void updateInventJournalTranferDesign()
{
    FormDataSource      inventJournalTable_DS       = this;
    InventJournalTable  inventJournalTable          = inventJournalTable_DS.cursor();
    InventParameters    inventParameters            = InventParameters::find();

    if (inventParameters.ETGEnableQualityParameter == NoYes::Yes
        && (inventJournalTable.JournalNameId == inventParameters.ETGBin2BinTransferJrnName
        || inventJournalTable.JournalNameId == inventParameters.ETGBinAdjustmentJrnName
        || inventJournalTable.JournalNameId == inventParameters.ETGBinTransferJournalName
        || inventJournalTable.JournalNameId == inventParameters.ETGLotTransferJrnName))
    {
        this.formRun().design().viewEditMode(ViewEditMode::View);
        FormDataSource inventJournalTransDS = this.formRun().dataSource(formDataSourceStr(InventJournalTransfer, InventJournalTrans));
        inventJournalTransDS.allowDelete(false);  
        inventJournalTable_DS.allowDelete(false); //added by ratna.

    }
}
